<?php
namespace NYMegaMenu;

defined( 'ABSPATH' ) || exit;

class Admin {
	public function hooks() {
		add_action( 'admin_menu', array( $this, 'menu' ) );
		add_action( 'admin_init', array( $this, 'settings' ) );
		add_action( 'wp_nav_menu_item_custom_fields', array( $this, 'item_fields' ), 10, 5 );
		add_action( 'wp_update_nav_menu_item', array( $this, 'save_item' ), 10, 3 );
		add_action( 'admin_enqueue_scripts', array( $this, 'assets' ) );
	}

	public function menu() {
		add_menu_page( __( 'NY Mega Menu', 'nymegamenu' ), __( 'NY Mega Menu', 'nymegamenu' ), 'edit_theme_options', 'nymegamenu', array( $this, 'locations_page' ), 'dashicons-menu', 61 );
		add_submenu_page( 'nymegamenu', __( 'Menu Locations', 'nymegamenu' ), __( 'Menu Locations', 'nymegamenu' ), 'edit_theme_options', 'nymegamenu', array( $this, 'locations_page' ) );
		add_submenu_page( 'nymegamenu', __( 'Menu Themes', 'nymegamenu' ), __( 'Menu Themes', 'nymegamenu' ), 'edit_theme_options', 'nymegamenu-themes', array( $this, 'themes_page' ) );
	}

	public function settings() { register_setting( 'nymegamenu', Settings::OPTION, array( 'sanitize_callback' => array( 'NYMegaMenu\\Settings', 'sanitize' ) ) ); }
	public function assets( $hook ) {
		if ( false === strpos( $hook, 'nav-menus' ) && false === strpos( $hook, 'nymegamenu' ) && 'post.php' !== $hook && 'post-new.php' !== $hook ) { return; }
		wp_enqueue_style( 'nymegamenu-admin', NYMEGAMENU_URL . 'assets/admin.css', array(), NYMEGAMENU_VERSION );
	}

	public function locations_page() {
		if ( ! current_user_can( 'edit_theme_options' ) ) { return; }
		$settings = Settings::all(); $locations = get_registered_nav_menus();
		?>
		<div class="wrap nymega-admin"><h1><?php esc_html_e( 'NY Mega Menu: Menu Locations', 'nymegamenu' ); ?></h1><p><?php esc_html_e( 'Enable a WordPress menu location, then configure its interaction and responsive behavior. Manage individual menu items in Appearance → Menus.', 'nymegamenu' ); ?></p><form method="post" action="options.php"><?php settings_fields( 'nymegamenu' ); ?><table class="widefat striped"><thead><tr><th><?php esc_html_e( 'Location', 'nymegamenu' ); ?></th><th><?php esc_html_e( 'Enabled', 'nymegamenu' ); ?></th><th><?php esc_html_e( 'Theme', 'nymegamenu' ); ?></th><th><?php esc_html_e( 'Behavior', 'nymegamenu' ); ?></th><th><?php esc_html_e( 'Responsive', 'nymegamenu' ); ?></th></tr></thead><tbody><?php foreach ( $locations as $key => $label ) : $profile = wp_parse_args( Settings::location( $key ), array( 'theme' => 'default', 'trigger' => 'click', 'layout' => 'horizontal', 'breakpoint' => 900 ) ); ?><tr><th><?php echo esc_html( $label ); ?><code><?php echo esc_html( $key ); ?></code></th><td><label><input type="checkbox" name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][enabled]" value="1" <?php checked( ! empty( $profile['enabled'] ) ); ?>> <?php esc_html_e( 'Use NY Mega Menu', 'nymegamenu' ); ?></label></td><td><select name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][theme]"><?php foreach ( $settings['themes'] as $theme_key => $theme ) : ?><option value="<?php echo esc_attr( $theme_key ); ?>" <?php selected( $profile['theme'], $theme_key ); ?>><?php echo esc_html( $theme['name'] ); ?></option><?php endforeach; ?></select></td><td><select name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][trigger]"><option value="click" <?php selected( $profile['trigger'], 'click' ); ?>><?php esc_html_e( 'Click', 'nymegamenu' ); ?></option><option value="hover" <?php selected( $profile['trigger'], 'hover' ); ?>><?php esc_html_e( 'Hover', 'nymegamenu' ); ?></option><option value="hover-intent" <?php selected( $profile['trigger'], 'hover-intent' ); ?>><?php esc_html_e( 'Hover intent', 'nymegamenu' ); ?></option></select><select name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][layout]"><option value="horizontal"><?php esc_html_e( 'Horizontal', 'nymegamenu' ); ?></option><option value="vertical" <?php selected( $profile['layout'], 'vertical' ); ?>><?php esc_html_e( 'Vertical', 'nymegamenu' ); ?></option><option value="accordion" <?php selected( $profile['layout'], 'accordion' ); ?>><?php esc_html_e( 'Accordion', 'nymegamenu' ); ?></option></select></td><td><label><?php esc_html_e( 'Breakpoint', 'nymegamenu' ); ?> <input type="number" min="480" max="1600" name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][breakpoint]" value="<?php echo esc_attr( $profile['breakpoint'] ); ?>"></label><br><label><input type="checkbox" name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][sticky]" value="1" <?php checked( ! empty( $profile['sticky'] ) ); ?>> <?php esc_html_e( 'Sticky', 'nymegamenu' ); ?></label> <label><input type="checkbox" name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][offcanvas]" value="1" <?php checked( ! empty( $profile['offcanvas'] ) ); ?>> <?php esc_html_e( 'Off-canvas', 'nymegamenu' ); ?></label> <label><input type="checkbox" name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][search]" value="1" <?php checked( ! empty( $profile['search'] ) ); ?>> <?php esc_html_e( 'Search', 'nymegamenu' ); ?></label> <label><input type="checkbox" name="nymegamenu_settings[locations][<?php echo esc_attr( $key ); ?>][cart]" value="1" <?php checked( ! empty( $profile['cart'] ) ); ?>> <?php esc_html_e( 'Cart', 'nymegamenu' ); ?></label></td></tr><?php endforeach; ?></tbody></table><?php submit_button(); ?></form></div><?php
	}

	public function themes_page() {
		if ( ! current_user_can( 'edit_theme_options' ) ) { return; } $settings = Settings::all();
		?><div class="wrap nymega-admin"><h1><?php esc_html_e( 'NY Mega Menu: Themes', 'nymegamenu' ); ?></h1><p><?php esc_html_e( 'Themes are reusable visual presets. Duplicate a row by adding a new unique key before saving.', 'nymegamenu' ); ?></p><form method="post" action="options.php"><?php settings_fields( 'nymegamenu' ); ?><table class="widefat striped"><thead><tr><th><?php esc_html_e( 'Key', 'nymegamenu' ); ?></th><th><?php esc_html_e( 'Name', 'nymegamenu' ); ?></th><th><?php esc_html_e( 'Colors', 'nymegamenu' ); ?></th><th><?php esc_html_e( 'Spacing / Radius', 'nymegamenu' ); ?></th></tr></thead><tbody><?php foreach ( $settings['themes'] as $key => $theme ) : ?><tr><th><code><?php echo esc_html( $key ); ?></code></th><td><input name="nymegamenu_settings[themes][<?php echo esc_attr( $key ); ?>][name]" value="<?php echo esc_attr( $theme['name'] ); ?>"></td><td><label><?php esc_html_e( 'Background', 'nymegamenu' ); ?> <input type="color" name="nymegamenu_settings[themes][<?php echo esc_attr( $key ); ?>][background]" value="<?php echo esc_attr( $theme['background'] ); ?>"></label> <label><?php esc_html_e( 'Text', 'nymegamenu' ); ?> <input type="color" name="nymegamenu_settings[themes][<?php echo esc_attr( $key ); ?>][text]" value="<?php echo esc_attr( $theme['text'] ); ?>"></label> <label><?php esc_html_e( 'Accent', 'nymegamenu' ); ?> <input type="color" name="nymegamenu_settings[themes][<?php echo esc_attr( $key ); ?>][accent]" value="<?php echo esc_attr( $theme['accent'] ); ?>"></label></td><td><input type="number" name="nymegamenu_settings[themes][<?php echo esc_attr( $key ); ?>][spacing]" value="<?php echo esc_attr( $theme['spacing'] ); ?>"> / <input type="number" name="nymegamenu_settings[themes][<?php echo esc_attr( $key ); ?>][radius]" value="<?php echo esc_attr( $theme['radius'] ); ?>"></td></tr><?php endforeach; ?></tbody></table><?php submit_button(); ?></form></div><?php
	}

	public function item_fields( $item_id, $item ) {
		$settings = Renderer::item_settings( $item_id ); $panels = get_posts( array( 'post_type' => 'nymega_panel', 'posts_per_page' => -1, 'post_status' => 'any' ) );
		wp_nonce_field( 'nymegamenu_item', 'nymegamenu_item_nonce' ); ?>
		<p class="description description-wide nymega-menu-fields"><strong><?php esc_html_e( 'NY Mega Menu', 'nymegamenu' ); ?></strong><br><label><?php esc_html_e( 'Display', 'nymegamenu' ); ?> <select name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][mode]"><option value="flyout" <?php selected( $settings['mode'], 'flyout' ); ?>><?php esc_html_e( 'Flyout', 'nymegamenu' ); ?></option><option value="mega" <?php selected( $settings['mode'], 'mega' ); ?>><?php esc_html_e( 'Mega panel', 'nymegamenu' ); ?></option></select></label> <label><?php esc_html_e( 'Panel', 'nymegamenu' ); ?> <select name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][panel_id]"><option value="0"><?php esc_html_e( 'Select a panel', 'nymegamenu' ); ?></option><?php foreach ( $panels as $panel ) : ?><option value="<?php echo esc_attr( $panel->ID ); ?>" <?php selected( $settings['panel_id'], $panel->ID ); ?>><?php echo esc_html( $panel->post_title ); ?></option><?php endforeach; ?></select></label><br><label><?php esc_html_e( 'Dashicon', 'nymegamenu' ); ?> <input name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][icon]" value="<?php echo esc_attr( $settings['icon'] ); ?>" placeholder="dashicons-admin-home"></label> <label><?php esc_html_e( 'Badge', 'nymegamenu' ); ?> <input name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][badge]" value="<?php echo esc_attr( $settings['badge'] ); ?>"></label><br><label><input type="checkbox" name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][hide_text]" value="1" <?php checked( $settings['hide_text'] ); ?>> <?php esc_html_e( 'Hide text', 'nymegamenu' ); ?></label> <label><input type="checkbox" name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][hide_arrow]" value="1" <?php checked( $settings['hide_arrow'] ); ?>> <?php esc_html_e( 'Hide arrow', 'nymegamenu' ); ?></label> <label><input type="checkbox" name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][disable_link]" value="1" <?php checked( $settings['disable_link'] ); ?>> <?php esc_html_e( 'Disable link', 'nymegamenu' ); ?></label> <label><input type="checkbox" name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][desktop]" value="1" <?php checked( $settings['desktop'] ); ?>> <?php esc_html_e( 'Desktop', 'nymegamenu' ); ?></label> <label><input type="checkbox" name="nymegamenu_item[<?php echo esc_attr( $item_id ); ?>][mobile]" value="1" <?php checked( $settings['mobile'] ); ?>> <?php esc_html_e( 'Mobile', 'nymegamenu' ); ?></label></p><?php
	}

	public function save_item( $menu_id, $menu_item_db_id ) {
		if ( ! current_user_can( 'edit_theme_options' ) || empty( $_POST['nymegamenu_item_nonce'] ) || ! wp_verify_nonce( sanitize_text_field( wp_unslash( $_POST['nymegamenu_item_nonce'] ) ), 'nymegamenu_item' ) ) { return; }
		$input = isset( $_POST['nymegamenu_item'][ $menu_item_db_id ] ) ? (array) wp_unslash( $_POST['nymegamenu_item'][ $menu_item_db_id ] ) : array();
		$data = array( 'mode' => in_array( $input['mode'] ?? '', array( 'mega', 'flyout' ), true ) ? $input['mode'] : 'flyout', 'panel_id' => absint( $input['panel_id'] ?? 0 ), 'icon' => sanitize_html_class( $input['icon'] ?? '' ), 'badge' => sanitize_text_field( $input['badge'] ?? '' ), 'hide_text' => empty( $input['hide_text'] ) ? 0 : 1, 'hide_arrow' => empty( $input['hide_arrow'] ) ? 0 : 1, 'disable_link' => empty( $input['disable_link'] ) ? 0 : 1, 'desktop' => empty( $input['desktop'] ) ? 0 : 1, 'mobile' => empty( $input['mobile'] ) ? 0 : 1, 'roles' => array() );
		update_post_meta( $menu_item_db_id, '_nymegamenu_item', $data );
	}
}
